sys_transform_script.script:
(function runTransformScript(source, map, log, target /*undefined onStart*/ ) {
    // Populate the Ignore fields (Ignore true/false, Ignore reason) for 
    // Import Set rows not marked ignore and whose Location reference
    // is still empty.

    // -- We compared each row's location code to invalid entries, and 
    //    marked these ignored.
    // -- We compared each row's location code to valid entries, and 
    //    populated the Location reference in these.
    //
    // So those not marked ignore, and which still do not have a Reference,
    // have a location code that is either empty or just not in the map
    // at all. So all these can get the same ignore message.
    var gr_is_row = new GlideRecord("x_42999_decision_0_hardware_location");
    gr_is_row.addQuery("sys_import_set", import_set.sys_id);
    gr_is_row.addQuery("u_ignore", false);
    gr_is_row.addEncodedQuery("u_location_refISEMPTY");
    gr_is_row.query();
    while (gr_is_row.hasNext()) {
        gr_is_row.next();
        gr_is_row.setValue("u_ignore", true);
        gr_is_row.setValue("u_ignore_reason", "location code empty/not mapped");
        gr_is_row.update();
    }
})(source, map, log, target);
